#!/usr/bin/env python3
import sys, socket, struct, time, os

# RuneScape 2004-style login client
# Usage: python /app/login.py <username>
# Password equals username

def read_exact(sock, n):
    data = b''
    while len(data) < n:
        chunk = sock.recv(n - len(data))
        if not chunk:
            raise ConnectionError('Socket closed')
        data += chunk
    return data

def jstr(s: bytes) -> bytes:
    # zero-terminated string
    return s + b"\x00"

def main():
    if len(sys.argv) != 2:
        print('Usage: python /app/login.py <username>')
        sys.exit(1)
    username = sys.argv[1]
    password = username

    host = '127.0.0.1'
    port = 43594  # typical RS2 login port

    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(5)
    s.connect((host, port))

    # Initial handshake: opcode 14 then expect server seed
    s.sendall(struct.pack('>B', 14))
    server_seed = 0
    try:
        # Some servers send a single byte then 8-byte seed; read permissively
        pre = s.recv(1)
        seed_bytes = s.recv(8)
        if len(seed_bytes) == 8:
            server_seed = struct.unpack('>q', seed_bytes)[0]
    except Exception:
        pass

    # Build login block (317-era):
    login_type = 16  # new connection
    magic = 255
    client_version = 317
    low_mem = 0

    payload = b''
    payload += struct.pack('>B', magic)
    payload += struct.pack('>H', client_version)
    payload += struct.pack('>B', low_mem)
    # 9 CRC ints (update keys), we'll send zeros
    payload += b''.join(struct.pack('>I', 0) for _ in range(9))

    # Security/RSA-like block
    client_seed = struct.unpack('>q', os.urandom(8))[0]
    rsa = b''
    rsa += struct.pack('>B', 10)
    rsa += struct.pack('>q', client_seed)
    rsa += struct.pack('>q', server_seed)
    rsa += jstr(password.encode('latin-1'))
    rsa += jstr(username.encode('latin-1'))

    payload += struct.pack('>H', len(rsa))
    payload += rsa

    header = struct.pack('>B', login_type) + struct.pack('>H', len(payload))
    s.sendall(header + payload)

    # Read response code
    try:
        resp = read_exact(s, 1)
    except Exception as e:
        print(f'Login failed: {e}')
        s.close()
        sys.exit(1)
    code = resp[0]
    if code != 2:
        print(f'Login failed, response code {code}')
        s.close()
        sys.exit(1)
    else:
        print('Login success')

    # Read a bit of post-login data, then logout
    s.settimeout(1)
    try:
        _ = s.recv(128)
    except Exception:
        pass

    # Send logout opcode (commonly 104)
    try:
        s.sendall(struct.pack('>B', 104))
    except Exception:
        pass
    time.sleep(0.5)
    s.close()

if __name__ == '__main__':
    main()
