#!/usr/bin/env python3
import sys, socket, struct, time, os, json

HOST = '127.0.0.1'
RS2_PORT = 43594
JSON_PORT = 43500

def read_exact(sock, n):
    data = b''
    while len(data) < n:
        chunk = sock.recv(n - len(data))
        if not chunk:
            raise ConnectionError('Socket closed')
        data += chunk
    return data

def try_rs2_login(username, password):
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(5)
    s.connect((HOST, RS2_PORT))
    # Initial handshake opcode 14 with dummy long
    s.sendall(struct.pack('>Bq', 14, 0))
    # Attempt to read seed bytes (optional)
    try:
        _ = s.recv(1)
        _ = s.recv(8)
    except Exception:
        pass
    # Build minimal 317-style login block
    login_type = 16
    magic = 255
    client_version = 317
    low_mem = 0

    payload = b''
    payload += struct.pack('>B', magic)
    payload += struct.pack('>H', client_version)
    payload += struct.pack('>B', low_mem)
    payload += b''.join(struct.pack('>I', 0) for _ in range(9))

    # Security block
    uname = username.encode('latin-1')
    pword = password.encode('latin-1')
    sec = b''
    sec += struct.pack('>B', 10)
    sec += struct.pack('>q', 0)
    sec += struct.pack('>q', 0)
    sec += struct.pack('>B', len(pword)) + pword
    sec += struct.pack('>B', len(uname)) + uname

    payload += struct.pack('>B', len(sec)) + sec
    header = struct.pack('>B', login_type) + struct.pack('>H', len(payload))
    s.sendall(header + payload)

    resp = read_exact(s, 1)
    code = resp[0]
    if code != 2:
        s.close()
        return False
    # Logout opcode (commonly 104)
    try:
        s.sendall(struct.pack('>B', 104))
    except Exception:
        pass
    time.sleep(0.2)
    s.close()
    return True

def recv_line(sock, timeout=5.0):
    sock.settimeout(timeout)
    data = b''
    try:
        while True:
            chunk = sock.recv(4096)
            if not chunk:
                break
            data += chunk
            if b"\n" in chunk:
                break
    except Exception:
        pass
    return data

def try_json_login(username, password):
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(5)
    s.connect((HOST, JSON_PORT))
    req = {"id": 1, "op": "login", "username": username, "password": password}
    s.sendall((json.dumps(req) + "\n").encode())
    resp_bytes = recv_line(s, timeout=5.0)
    lines = [ln for ln in resp_bytes.decode(errors='ignore').splitlines() if ln.strip().startswith('{')]
    if not lines:
        s.close()
        return False
    try:
        msg = json.loads(lines[-1])
    except Exception:
        s.close()
        return False
    code = msg.get('response')
    ok = code in (0, 2, 'OK', 'ok', 'success', 'SUCCESS')
    # logout
    try:
        s.sendall((json.dumps({"id": 2, "op": "logout"}) + "\n").encode())
    except Exception:
        pass
    s.close()
    return ok

def main():
    if len(sys.argv) != 2:
        print('Usage: python /app/login.py <username>')
        sys.exit(1)
    username = sys.argv[1]
    password = username

    # Prefer RS2 on 43594 if reachable
    rs2_first = True
    # allow override via env
    use_json_only = os.getenv('USE_JSON_ONLY') == '1'

    if not use_json_only:
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.settimeout(2)
            s.connect((HOST, RS2_PORT))
            s.close()
            rs2_first = True
        except Exception:
            rs2_first = False

    success = False
    if rs2_first and not use_json_only:
        try:
            success = try_rs2_login(username, password)
        except Exception:
            success = False
    if not success:
        try:
            success = try_json_login(username, password)
        except Exception:
            success = False

    if success:
        print('Login success')
        sys.exit(0)
    else:
        print('Login failed')
        sys.exit(1)

if __name__ == '__main__':
    main()
